import {
  ClassField,
  StringField,
  StringFieldOptional,
} from "../../../decorators/field.decorators.ts";

export class PaymentStatusMeta {
  @StringField()
  request_id!: string;

  @StringField()
  source_app!: string;

  @StringField()
  contract_number!: string;

  @StringField()
  srn!: string;

  @StringField()
  msg_type!: string;
}

export class PaymentStatusData {
  @StringField()
  status!: string;

  @StringField()
  status_desc!: string;

  @StringField()
  debit_account!: string;

  @StringField()
  txn_ts!: string;

  @StringField()
  credit_account!: string;

  @StringField()
  amount!: string;

  @StringFieldOptional()
  srn?: string;
}

export class PaymentStatusResponse {
  @StringField()
  response_code!: string;

  @StringFieldOptional()
  response_status?: string;

  @StringFieldOptional()
  response_detail?: string;

  @StringField()
  response_description!: string;

  @ClassField(() => PaymentStatusMeta, { nullable: true })
  meta_info?: PaymentStatusMeta | null;

  @ClassField(() => PaymentStatusData, { nullable: true })
  status?: PaymentStatusData | null;

  @ClassField(() => PaymentStatusData, { nullable: true, isArray: true })
  response_data?: PaymentStatusData[] | null;
}

export class VerifyPaymentStatusResponseDto {
  @StringField()
  account_number!: string;

  @StringField()
  transaction_id!: string;

  @StringField()
  request_id!: string;

  @StringField()
  bene_account_number!: string;

  @StringField()
  status_code!: string;

  @StringField()
  status_message!: string;

  @StringField()
  status_description!: string;

  @StringFieldOptional()
  payment_status?: string;

  @StringFieldOptional()
  payment_status_desc?: string;

  @StringFieldOptional()
  amount?: string;

  @StringFieldOptional()
  debit_account?: string;

  @StringFieldOptional()
  credit_account?: string;

  @StringFieldOptional()
  transaction_timestamp?: string;
}
